public static int FindStrongestEnemy(List<int> healthValues)
{
    if (healthValues.Count == 0)
    {
        return -1;
    }

    int maxIndex = 0;
    for (int i = 1; i < healthValues.Count; i++)
    {
        if (healthValues[i] > healthValues[maxIndex])
        {
            maxIndex = i;
        }
    }
    return maxIndex;
}

