public class Weapon
{
    private string name;
    private int baseDamage;
    private float critMultiplier;

    public Weapon(string name, int baseDamage, float critMultiplier)
    {
        this.name = name;
        this.baseDamage = baseDamage;
        this.critMultiplier = critMultiplier;
    }

    public int CalculateDamage(bool isCritical)
    {
        if (isCritical)
        {
            return (int)(baseDamage * critMultiplier);
        }
        return baseDamage;
    }
}

bool isColliding = A.Left < B.Right && A.Right > B.Left && A.Top < B.Bottom && A.Bottom > B.Top;

// If you change A.Left < B.Right to A.Left > B.Right, the condition
// checks whether A is entirely to the RIGHT of B on the X axis.
// This inverts the X-overlap check, meaning the function returns true
// when objects are NOT overlapping horizontally (and false when they are).
// The result: collisions are detected everywhere EXCEPT where the objects
// actually overlap, causing the game to respond to phantom collisions
// across the entire screen while ignoring real ones.

velocity += acceleration * deltaTime;
position += velocity * deltaTime;

// If you swap the order (update position first, then velocity),
// position uses the OLD velocity from the previous frame before
// the current frame's acceleration is applied. This means
// acceleration takes one extra frame to affect position,
// creating a one-frame lag in physics response. The character
// feels slightly sluggish because movement changes are delayed
// by one frame. For gravity, this means the character starts
// falling one frame later than expected, and jumps feel slightly
// floatier because the upward velocity is applied before gravity
// reduces it.

public class SaveData
{
    public string PlayerName { get; set; }
    public int Score { get; set; }
}

